export class Box { constructor(props) { this.props = props || {}; } }
export class Text { constructor(props, children) { this.props = props || {}; this.children = children; } }
export class Static { constructor(props) { this.props = props || {}; } }
export function useApp() { return { stdout: { write: () => {} }, stderr: { write: () => {} }, stdin: { on: () => {} } }; }
export function useInput() {} export function useStdin() { return { on: () => {} }; }
export function useStdout() { return { write: () => {} }; } export function useStderr() { return { write: () => {} }; }
export function render(node) { return { unmount: () => {}, waitUntilExit: () => Promise.resolve() }; }
export default { Box, Text, Static, useApp, useInput, useStdin, useStdout, useStderr, render };
